def test_flatten_simple():
    from your_module import flatten_dict
    data = {"a": 1, "b": 2}
    assert flatten_dict(data) == {"a": 1, "b": 2}

def test_flatten_nested():
    from your_module import flatten_dict
    data = {"a": {"b": {"c": 1}}, "d": 2}
    result = flatten_dict(data)
    assert result == {"a.b.c": 1, "d": 2}

def test_flatten_multiple_levels():
    from your_module import flatten_dict
    data = {"a": {"x": 1}, "b": {"y": {"z": 2}}, "c": 3}
    result = flatten_dict(data)
    assert result == {"a.x": 1, "b.y.z": 2, "c": 3}

def test_flatten_with_custom_separator():
    from your_module import flatten_dict
    data = {"a": {"b": 1}}
    result = flatten_dict(data, sep="_")
    assert result == {"a_b": 1}

def test_empty_dict():
    from your_module import flatten_dict
    assert flatten_dict({}) == {}

def test_nested_empty_dict():
    from your_module import flatten_dict
    data = {"a": {}}
    result = flatten_dict(data)
    assert result == {}  # no entries produced

def test_non_string_keys():
    from your_module import flatten_dict
    data = {1: {2: 3}}
    # keys will be converted to string implicitly via f-string
    result = flatten_dict(data)
    assert result == {"1.2": 3}

def test_mixed_value_types():
    from your_module import flatten_dict
    data = {"a": {"b": None}, "c": True, "d": 5.5}
    assert flatten_dict(data) == {"a.b": None, "c": True, "d": 5.5}

def test_error_non_dict_input():
    from your_module import flatten_dict
    import pytest
    with pytest.raises(AttributeError):
        flatten_dict(123)  # calling .items() on non-dict triggers AttributeError

def test_error_invalid_sep_type():
    from your_module import flatten_dict
    import pytest
    # sep must be a string because it is concatenated; otherwise TypeError
    with pytest.raises(TypeError):
        flatten_dict({"a": {"b": 1}}, sep=5)

